const items = $('Read Enriched Jobs').all();
const enriched = items.filter(i => i.json.status === 'enriched');
if (enriched.length === 0) throw new Error('No enriched jobs found');
return enriched.map(i => ({ json: i.json }));

const job = $('Filter Enriched Only').item.json;
const allRows = $('Read Master Resume').all().map(i => i.json);

// Filter to only actual resume rows (have 'section' field, not job rows leaking through)
const resumeRows = allRows.filter(r => r.section && r.section.trim());

// Deduplicate by section name (in case of pipeline data duplication)
const seen = new Set();
const uniqueRows = resumeRows.filter(r => {
  const key = r.section.trim();
  if (seen.has(key)) return false;
  seen.add(key);
  return true;
});

const skipSections = new Set(['role_to_resume_mapping']);
const masterResume = uniqueRows
  .filter(r => !skipSections.has(r.section) && (r.content || '').trim())
  .map(r => (r.section || '').toUpperCase() + ':\n' + (r.content || ''))
  .join('\n\n');

if (masterResume.length < 100) throw new Error('Resume content too short (' + masterResume.length + ' chars). Check Master Resume tab.');

let companyResearch = job.company_research || '';
if (typeof companyResearch === 'string' && companyResearch.startsWith('{')) {
  try { companyResearch = JSON.parse(companyResearch); } catch(e) {}
}

return [{ json: {
  ...job,
  company_research: companyResearch,
  master_resume: masterResume.slice(0, 15000),
  selected_resume_type: 'unified'
} }];

const job = $('Prepare Fit Input').item.json;
const raw = $json.choices?.[0]?.message?.content || '{}';
let fit;
try { fit = JSON.parse(raw); } catch (e) { fit = { fit_score: 0, decision: 'needs_review', parse_error: true }; }
return [{ json: { ...job, fit } }];

const job = $('Parse Fit Score').item.json;
const raw = $json.choices?.[0]?.message?.content || '{}';
let resume;
try { resume = JSON.parse(raw); } catch (e) { resume = { parse_error: true, document_title: `Resume - ${job.title} - ${job.company_name}` }; }
return [{ json: {
  ...job,
  resume_markdown: resume.resume_markdown || '',
  resume_html: resume.resume_html || '',
  tailoring_rationale: resume.tailoring_rationale || '',
  status: 'needs_review',
  fit_score: job.fit.fit_score,
  fit_decision: job.fit.decision,
  fit_rationale: job.fit.rationale || '',
  matched_requirements: (job.fit.matched_requirements || []).join(', '),
  missing_requirements: (job.fit.missing_requirements || []).join(', '),
  updated_at: new Date().toISOString()
} }];

const job = $json;
return [{ json: {
  ...job,
  status: job.fit.fit_score >= 65 ? 'needs_review' : 'rejected',
  fit_score: job.fit.fit_score,
  fit_decision: job.fit.decision,
  fit_rationale: job.fit.rationale || '',
  matched_requirements: (job.fit.matched_requirements || []).join(', '),
  missing_requirements: (job.fit.missing_requirements || []).join(', '),
  updated_at: new Date().toISOString()
} }];

const job = $json;
const desc = (job.description || '').slice(0, 4000).replace(/[\n\r\t]/g, ' ');
if (desc.length < 200) throw new Error('Description too short (' + desc.length + ' chars) for job ' + job.job_id + ' - likely not enriched');
const resume = (job.master_resume || '').replace(/[\n\r\t]/g, ' ');
let companyResearch = '';
if (typeof job.company_research === 'object' && job.company_research) {
  companyResearch = JSON.stringify(job.company_research).slice(0, 2000).replace(/[\n\r\t]/g, ' ');
} else if (typeof job.company_research === 'string') {
  companyResearch = job.company_research.slice(0, 2000).replace(/[\n\r\t]/g, ' ');
}

const body = {
  messages: [
    {
      role: "system",
      content: "You are an expert career strategist. Evaluate job relevance based on resume evidence, job description, and company context. Return strict JSON: job_id, fit_score (0-100), decision (reject|needs_review|generate_resume), rationale, matched_requirements (array), missing_requirements (array), resume_evidence (array), company_signals (array), risk_flags (array). Scoring: 90-100 excellent, 80-89 strong generate resume, 65-79 needs review, 40-64 weak reject, 0-39 irrelevant. Do not inflate. Do not assume skills not in resume."
    },
    {
      role: "user",
      content: "JOB ID: " + job.job_id + " JOB TITLE: " + job.title + " COMPANY: " + job.company_name + " LOCATION: " + job.location + " SEARCH KEYWORDS: " + (job.search_keywords || '') + " RESUME TYPE: " + job.selected_resume_type + " JOB DESCRIPTION: " + desc + " COMPANY RESEARCH: " + companyResearch + " MASTER RESUME: " + resume
    }
  ],
  response_format: { type: "json_object" },
  max_tokens: 1500
};

return [{ json: { ...job, body_string: JSON.stringify(body) } }];

